class RecordingBuilder
  def initialize(bucket:, creator:)
    @bucket = bucket
    @creator = creator
  end

  def build_message(subject:, body:)
    message = Message.new(subject: subject, body: body)
    Recording.new(recordable: message, bucket: @bucket, creator: @creator)
  end

  def build_comment(body:)
    comment = Comment.new(body: body)
    Recording.new(recordable: comment, bucket: @bucket, creator: @creator)
  end
end
